CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), telegram_user_id bigint UNIQUE, telegram_username text, locale text NOT NULL DEFAULT 'ru', timezone text NOT NULL DEFAULT 'Europe/Moscow', status text NOT NULL DEFAULT 'active' CHECK (status IN ('active','disabled','deletion_pending')), settings jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE telegram_updates (update_id bigint PRIMARY KEY, user_id uuid REFERENCES users(id), update_kind text NOT NULL CHECK (update_kind IN ('message','callback','command')), received_at timestamptz NOT NULL DEFAULT now(), processed_at timestamptz, result text NOT NULL CHECK (result IN ('accepted','duplicate','ignored','failed')));
CREATE TABLE journal_entries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), source_type text NOT NULL CHECK (source_type IN ('telegram_text','telegram_voice','web','import')), source_message_id bigint, source_sent_at timestamptz NOT NULL, received_at timestamptz NOT NULL DEFAULT now(), raw_text_ciphertext bytea NOT NULL, encryption_key_version int NOT NULL, content_sha256 bytea NOT NULL, language text, processing_status text NOT NULL DEFAULT 'queued' CHECK (processing_status IN ('queued','processing','parsed','needs_input','failed','deleted')), deleted_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX journal_entries_source_message_key ON journal_entries(user_id, source_type, source_message_id) WHERE source_message_id IS NOT NULL;
CREATE TABLE jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), kind text NOT NULL, payload jsonb NOT NULL, status text NOT NULL DEFAULT 'queued' CHECK (status IN ('queued','running','succeeded','retryable_failed','terminal_failed')), available_at timestamptz NOT NULL DEFAULT now(), locked_at timestamptz, locked_by text, attempts int NOT NULL DEFAULT 0 CHECK (attempts >= 0), max_attempts int NOT NULL CHECK (max_attempts > 0), last_error_code text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX jobs_claim_idx ON jobs(status, available_at) WHERE status IN ('queued','retryable_failed');
CREATE TABLE outbox_messages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), kind text NOT NULL, payload jsonb NOT NULL, status text NOT NULL DEFAULT 'queued' CHECK (status IN ('queued','running','succeeded','retryable_failed','terminal_failed')), available_at timestamptz NOT NULL DEFAULT now(), attempts int NOT NULL DEFAULT 0, max_attempts int NOT NULL DEFAULT 5, last_error_code text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
